// Festival dates (India) — update annually
const festivals = [
  { name: 'Diwali',      date: '2026-10-20', daysNotice: 30 },
  { name: 'Christmas',   date: '2026-12-25', daysNotice: 21 },
  { name: "New Year",    date: '2027-01-01', daysNotice: 21 },
  { name: 'Holi',        date: '2027-03-01', daysNotice: 21 },
  { name: "Valentine's", date: '2027-02-14', daysNotice: 14 },
  { name: 'Eid',         date: '2027-03-31', daysNotice: 21 },
];

const today = new Date();
const upcoming = festivals.filter(f => {
  const fest = new Date(f.date);
  const diff = Math.floor((fest - today) / (1000 * 60 * 60 * 24));
  return diff >= 0 && diff <= f.daysNotice;
});

return upcoming.map(f => ({ json: f }));
